import { useEffect, useState } from "react";

function Admin() {
    const [application, setApplication] = useState([]);

    useEffect(() => {
        fetch("http://localhost:5000/application", {
            headers: {
                Authorization: `Bearer ${localStorage.getItem("token")}`
            }
        })

            .then(res => res.json())
            .then(data => setApplication(data))
    }, [])

    const updateStatus = async (id, status) => {
        const response = await fetch(`http://localhost:5000/update-status/${id}`, {
            method: "PUT",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ status })
        });
        const data = await response.json();
        alert(data.message);
        window.location.reload();
    }

    return (
        <div className="container">
            <h2>Admin Panel</h2>

            <table border="1" cellPadding="10" width="1%">

                <thead>
                    <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Course</th>
                        <th>Status</th>
                        <th>Action</th>
                    </tr>
                </thead>

                <tbody>
                    {
                        application.map((item, index) => (
                            <tr key={index}>
                                <td>{item.name}</td>
                                <td>{item.email}</td>
                                <td>{item.course}</td>

                                <td>
                                    <span style={{
                                        color: item.status === "approved" ? "green" : item.status === "rejected" ? "red" : "orange"
                                    }}>
                                        {item.status}
                                    </span>
                                </td>

                                <td>
                                    <button onClick={() => updateStatus(item._id, "approved")}>Approve</button>
                                    <button onClick={() => updateStatus(item._id, "rejected")}>Reject</button>
                                </td>
                            </tr>

                        ))
                    }
                </tbody>
            </table>
        </div>
    )
}

export default Admin;
